#[cfg(test)]
mod mldsa_key_tests {
    use bouncycastle_core::errors::SignatureError;
    use bouncycastle_core::key_material::{
        KeyMaterial256, KeyMaterialTrait, KeyType, do_hazardous_operations,
    };
    use bouncycastle_core::traits::{SecurityStrength, SignaturePrivateKey, SignaturePublicKey};
    use bouncycastle_core_test_framework::signature::TestFrameworkSignatureKeys;
    use bouncycastle_hex as hex;
    use bouncycastle_mldsa::{
        MLDSA44, MLDSA44PrivateKey, MLDSA44PrivateKeyExpanded, MLDSA44PublicKey,
        MLDSA44PublicKeyExpanded, MLDSA65, MLDSA65PrivateKey, MLDSA65PrivateKeyExpanded,
        MLDSA65PublicKey, MLDSA65PublicKeyExpanded, MLDSA87, MLDSA87PrivateKey,
        MLDSA87PrivateKeyExpanded, MLDSA87PublicKey, MLDSA87PublicKeyExpanded,
        MLDSAPrivateKeyTrait, MLDSATrait,
    };
    use bouncycastle_mldsa::{
        MLDSA44_PK_LEN, MLDSA44_SK_LEN, MLDSA65_PK_LEN, MLDSA65_SK_LEN, MLDSA87_PK_LEN,
        MLDSA87_SK_LEN,
    };

    #[test]
    fn core_framework_tests() {
        let tf = TestFrameworkSignatureKeys::new();

        tf.test_keys::<MLDSA44PublicKey, MLDSA44PrivateKey, MLDSA44_PK_LEN, MLDSA44_SK_LEN>(
            MLDSA44::keygen,
        );
        tf.test_keys::<MLDSA65PublicKey, MLDSA65PrivateKey, MLDSA65_PK_LEN, MLDSA65_SK_LEN>(
            MLDSA65::keygen,
        );
        tf.test_keys::<MLDSA87PublicKey, MLDSA87PrivateKey, MLDSA87_PK_LEN, MLDSA87_SK_LEN>(
            MLDSA87::keygen,
        );
    }

    #[test]
    fn pk_from_sk() {
        /* MLDSA44 */
        let expected_sk_bytes: [u8; MLDSA44_SK_LEN] = hex::decode("").unwrap()
            .try_into().unwrap();
        let expected_pk_bytes: [u8; MLDSA44_PK_LEN] = hex::decode("").unwrap()
            .try_into().unwrap();

        // Decode and re-encode the sk, make sure you get the same thing
        let expected_sk = MLDSA44PrivateKey::from_bytes(&expected_sk_bytes).unwrap();
        let sk_bytes = expected_sk.encode();
        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());

        // Decode and re-encode the pk, make sure you get the same thing
        let decoded_pk = MLDSA44PublicKey::from_bytes(&expected_pk_bytes).unwrap();
        let pk_bytes = decoded_pk.encode();
        assert_eq!(pk_bytes.len(), expected_pk_bytes.len());
        assert_eq!(pk_bytes, expected_pk_bytes.as_slice());

        // test re-deriving pk from sk
        let pk1 = expected_sk.derive_pk();
        assert_eq!(pk1, decoded_pk);
    }

    #[test]
    fn encode_decode() {
        let seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();

        let (pk1, sk1) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let pk1_bytes = pk1.encode();
        let sk1_bytes = sk1.encode();

        let (pk2, sk2) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let pk2_bytes = pk2.encode();
        assert_eq!(pk1_bytes, pk2_bytes);

        let sk2_bytes = sk2.encode();
        assert_eq!(sk1_bytes, sk2_bytes);

        // test encode_out
        let mut pk1_bytes_out = [0u8; MLDSA44_PK_LEN];
        let bytes_written = pk1.encode_out(&mut pk1_bytes_out);
        assert_eq!(bytes_written, MLDSA44_PK_LEN);

        let mut sk1_bytes_out = [0u8; MLDSA44_SK_LEN];
        let bytes_written = sk1.encode_out(&mut sk1_bytes_out);
        assert_eq!(bytes_written, MLDSA44_SK_LEN);

        assert_eq!(pk1_bytes, pk1_bytes_out);
        assert_eq!(sk1_bytes, sk1_bytes_out);

        /* Expanded keys */

        let (pk1, sk1) = MLDSA65::keygen_from_seed(&seed).unwrap();
        let pk1_expanded = MLDSA65PublicKeyExpanded::from(&pk1);
        let sk1_expanded = MLDSA65PrivateKeyExpanded::from(&sk1);
        let pk1_bytes = pk1_expanded.encode();
        let sk1_bytes = sk1_expanded.encode();

        let (pk2, sk2) = MLDSA65::keygen_from_seed(&seed).unwrap();
        let pk2_expanded = MLDSA65PublicKeyExpanded::from(&pk2);
        let sk2_expanded = MLDSA65PrivateKeyExpanded::from(&sk2);
        let pk2_bytes = pk2_expanded.encode();
        assert_eq!(pk1_bytes, pk2_bytes);

        let sk2_bytes = sk2_expanded.encode();
        assert_eq!(sk1_bytes, sk2_bytes);

        // test encode_out
        let mut pk1_bytes_out = [0u8; MLDSA65_PK_LEN];
        let bytes_written = pk1_expanded.encode_out(&mut pk1_bytes_out);
        assert_eq!(bytes_written, MLDSA65_PK_LEN);

        let mut sk1_bytes_out = [0u8; MLDSA65_SK_LEN];
        let bytes_written = sk1.encode_out(&mut sk1_bytes_out);
        assert_eq!(bytes_written, MLDSA65_SK_LEN);

        assert_eq!(pk1_bytes, pk1_bytes_out);
        assert_eq!(sk1_bytes, sk1_bytes_out);

        let bytes_written = sk1_expanded.encode_out(&mut sk1_bytes_out);
        assert_eq!(bytes_written, MLDSA65_SK_LEN);
        assert_eq!(sk1_expanded.encode(), sk2_expanded.encode());
    }

    #[test]
    fn seed() {
        let seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();

        // todo change mlkem to also hold the whole keymaterial?

        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed).unwrap();

        assert_eq!(sk.seed(), Some(&seed));

        // it'll reject a keyen with a seed too weak, and preserve the seed otherwise
        let mut seed128 = seed.clone();
        do_hazardous_operations(&mut seed128, |seed128| {
            seed128.set_security_strength(SecurityStrength::_128bit)
        })
        .unwrap();

        let mut seed192 = seed.clone();
        do_hazardous_operations(&mut seed192, |seed192| {
            seed192.set_security_strength(SecurityStrength::_192bit)
        })
        .unwrap();

        let mut seed256 = seed.clone();
        do_hazardous_operations(&mut seed256, |seed256| {
            seed256.set_security_strength(SecurityStrength::_256bit)
        })
        .unwrap();

        // MLDSA44
        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed128).unwrap();
        assert_eq!(sk.seed(), Some(&seed128));

        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed192).unwrap();
        assert_eq!(sk.seed(), Some(&seed192));

        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed256).unwrap();
        assert_eq!(sk.seed(), Some(&seed256));

        // MLDSA65
        match MLDSA65::keygen_from_seed(&seed128) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => {
                panic!("unexpected error")
            }
        }

        let (_pk, sk) = MLDSA65::keygen_from_seed(&seed192).unwrap();
        assert_eq!(sk.seed(), Some(&seed192));

        let (_pk, sk) = MLDSA65::keygen_from_seed(&seed256).unwrap();
        assert_eq!(sk.seed(), Some(&seed256));

        // MLDSA87
        match MLDSA87::keygen_from_seed(&seed128) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => {
                panic!("unexpected error")
            }
        }
        match MLDSA87::keygen_from_seed(&seed192) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => {
                panic!("unexpected error")
            }
        }
        let (_pk, sk) = MLDSA87::keygen_from_seed(&seed256).unwrap();
        assert_eq!(sk.seed(), Some(&seed256));

        // now load a key from bytes so that it doesn't have a seed
        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let sk_bytes = sk.encode();
        let sk_no_seed = MLDSA44PrivateKey::from_bytes(&sk_bytes).unwrap();
        assert!(sk_no_seed.seed().is_none());

        /* Expanded key */
        let (_pk, sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let sk_expanded = MLDSA44PrivateKeyExpanded::from(&sk);
        match sk_expanded.seed() {
            Some(s) => assert_eq!(s, &seed),
            None => panic!("Expected expanded key to have seed"),
        }

        // now try an expanded key that doesn't have a seed
        let sk_expanded_no_seed = MLDSA44PrivateKeyExpanded::from(&sk_no_seed);
        assert!(sk_expanded_no_seed.seed().is_none());
    }

    #[test]
    fn invalid_key_load() {
        // test loading a private key with coeffs that are out of range according to
        // FIPS 204: Algorithm 25 skDecode(𝑠𝑘)
        //  ▷ this may lie outside [−𝜂, 𝜂] if input is malformed

        // https://github.com/randombit/wycheproof-rs/blob/master/src/data/mldsa_65_sign_noseed_test.json#L667-L706
        //  "tcId": 56,
        //  "comment": "private key with s1 vector out of range",
        let invalid_sk = hex::decode("").unwrap();

        match MLDSA65PrivateKey::from_bytes(invalid_sk.as_slice()) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }

        // https://github.com/randombit/wycheproof-rs/blob/master/src/data/mldsa_65_sign_noseed_test.json#L689
        //  "tcId": 57,
        //  "comment": "private key with s2 vector out of range",
        let invalid_sk = hex::decode("").unwrap();

        match MLDSA65PrivateKey::from_bytes(invalid_sk.as_slice()) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }

        // We do not need to test out-of-range public keys because FIPS 204 Alg 23 pkDecode() states
        // that SimpleBitUnpack() will always return a result in range.

        // key is wrong length

        let (pk, sk) = MLDSA65::keygen().unwrap();
        // too small
        let pk_bytes = pk.encode();
        let sk_bytes = sk.encode();
        match MLDSA65PublicKey::from_bytes(&pk_bytes[..MLDSA65_PK_LEN - 1]) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PublicKeyExpanded::from_bytes(&pk_bytes[..MLDSA65_PK_LEN - 1]) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PrivateKey::from_bytes(&sk_bytes[..MLDSA65_SK_LEN - 1]) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PrivateKeyExpanded::from_bytes(&sk_bytes[..MLDSA65_SK_LEN - 1]) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }

        // too big
        let mut pk_bytes_big = [1u8; MLDSA65_PK_LEN + 1];
        pk_bytes_big[..MLDSA65_PK_LEN].copy_from_slice(&pk_bytes);

        let mut sk_bytes_big = [1u8; MLDSA65_SK_LEN + 1];
        sk_bytes_big[..MLDSA65_SK_LEN].copy_from_slice(&sk_bytes);

        match MLDSA65PublicKey::from_bytes(&pk_bytes_big) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PublicKeyExpanded::from_bytes(&pk_bytes_big) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PrivateKey::from_bytes(&sk_bytes_big) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
        match MLDSA65PrivateKeyExpanded::from_bytes(&sk_bytes_big) {
            Err(SignatureError::DecodingError(_)) => { /* good */ }
            _ => panic!("Expected malformed key to be rejected"),
        }
    }

    #[test]
    fn test_eq() {
        // MLDSA-44
        {
            let (pk, sk) = MLDSA44::keygen().unwrap();

            // basic equality checks
            assert_eq!(pk, pk);
            assert_eq!(pk, pk.clone());
            assert_eq!(pk, MLDSA44PublicKey::from_bytes(&pk.encode()).unwrap());

            assert_eq!(sk, sk);
            assert_eq!(sk, sk.clone());
            assert_eq!(sk, MLDSA44PrivateKey::from_bytes(&sk.encode()).unwrap());

            let mut sk_bytes = [0u8; MLDSA44_SK_LEN];
            sk.encode_out(&mut sk_bytes);
            assert_eq!(sk_bytes, sk.encode());

            // inequality checks
            let mut bytes = pk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(pk, MLDSA44PublicKey::from_bytes(&bytes).unwrap());

            let mut bytes = sk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(sk, MLDSA44PrivateKey::from_bytes(&bytes).unwrap());
        }

        // MLDSA-65
        mldsa65();
        fn mldsa65() {
            let (pk, sk) = MLDSA65::keygen().unwrap();

            // basic equality checks
            assert_eq!(pk, pk);
            assert_eq!(pk, pk.clone());
            assert_eq!(pk, MLDSA65PublicKey::from_bytes(&pk.encode()).unwrap());

            assert_eq!(sk, sk);
            assert_eq!(sk, sk.clone());
            assert_eq!(sk, MLDSA65PrivateKey::from_bytes(&sk.encode()).unwrap());

            // inequality checks
            let mut bytes = pk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(pk, MLDSA65PublicKey::from_bytes(&bytes).unwrap());

            let mut bytes = sk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(sk, MLDSA65PrivateKey::from_bytes(&bytes).unwrap());
        }

        // MLDSA-87
        mldsa87();
        fn mldsa87() {
            let (pk, sk) = MLDSA87::keygen().unwrap();

            // basic equality checks
            assert_eq!(pk, pk);
            assert_eq!(pk, pk.clone());
            assert_eq!(pk, MLDSA87PublicKey::from_bytes(&pk.encode()).unwrap());

            assert_eq!(sk, sk);
            assert_eq!(sk, sk.clone());
            assert_eq!(sk, MLDSA87PrivateKey::from_bytes(&sk.encode()).unwrap());

            // inequality checks
            let mut bytes = pk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(pk, MLDSA87PublicKey::from_bytes(&bytes).unwrap());

            let mut bytes = sk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(sk, MLDSA87PrivateKey::from_bytes(&bytes).unwrap());
        }

        /* Expanded keys */
        expanded_keys();
        fn expanded_keys() {
            let (pk, sk) = MLDSA65::keygen().unwrap();
            let pk_expanded = MLDSA65PublicKeyExpanded::from_bytes(&pk.encode()).unwrap();
            let sk_expanded = MLDSA65PrivateKeyExpanded::from_bytes(&sk.encode()).unwrap();

            // basic equality checks
            assert_eq!(pk_expanded, pk_expanded);
            assert_eq!(pk_expanded, pk_expanded.clone());
            assert_eq!(pk_expanded, MLDSA65PublicKeyExpanded::from_bytes(&pk.encode()).unwrap());
            assert_eq!(pk_expanded.encode(), pk.encode());

            assert_eq!(sk_expanded, sk_expanded);
            assert_eq!(sk_expanded, sk_expanded.clone());
            assert_eq!(sk_expanded, MLDSA65PrivateKeyExpanded::from_bytes(&sk.encode()).unwrap());
            assert_eq!(sk_expanded.encode(), sk.encode());
            assert_eq!(sk_expanded.encode(), sk.encode());

            let mut sk_bytes = [0u8; MLDSA65_SK_LEN];
            let bytes_writen = sk_expanded.encode_out(&mut sk_bytes);
            assert_eq!(bytes_writen, MLDSA65_SK_LEN);
            assert_eq!(sk_bytes, sk.encode());

            assert_eq!(sk_expanded, sk_expanded);
            assert_eq!(sk_expanded, sk_expanded.clone());
            assert_eq!(sk_expanded, MLDSA65PrivateKeyExpanded::from_bytes(&sk.encode()).unwrap());
            assert_eq!(sk_expanded.encode(), sk.encode());

            // inequality checks
            let mut bytes = pk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(pk_expanded, MLDSA65PublicKeyExpanded::from_bytes(&bytes).unwrap());

            let mut bytes = sk.encode();
            bytes[17] ^= 0x01;
            assert_ne!(sk_expanded, MLDSA65PrivateKeyExpanded::from_bytes(&bytes).unwrap());
        }
    }

    /// Tests that no private data is displayed
    #[test]
    fn test_display() {
        let (pk44, sk44) = MLDSA44::keygen().unwrap();
        let (pk65, sk65) = MLDSA65::keygen().unwrap();
        let (pk87, sk87) = MLDSA87::keygen().unwrap();

        /*** MLDSAPublicKey ***/
        // fmt

        let pk_str = format!("{}", pk44);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-44, pub_key_hash (tr):"));

        let pk_str = format!("{}", pk65);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-65, pub_key_hash (tr):"));

        let pk_str = format!("{}", pk87);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-87, pub_key_hash (tr):"));

        // debug
        let pk_str = format!("{:?}", pk44);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-44, pub_key_hash (tr):"));

        let pk_str = format!("{:?}", pk65);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-65, pub_key_hash (tr):"));

        let pk_str = format!("{:?}", pk87);
        assert!(pk_str.contains("MLDSAPublicKey { alg: ML-DSA-87, pub_key_hash (tr):"));

        /*** MLDSAPrivateKey ***/
        // fmt
        let sk_str = format!("{}", sk44);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-44, pub_key_hash (tr):"));

        let sk_str = format!("{}", sk65);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-65, pub_key_hash (tr):"));

        let sk_str = format!("{}", sk87);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-87, pub_key_hash (tr):"));

        // debug
        let sk_str = format!("{:?}", sk44);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-44, pub_key_hash (tr):"));

        let sk_str = format!("{:?}", sk65);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-65, pub_key_hash (tr):"));

        let sk_str = format!("{:?}", sk87);
        assert!(sk_str.contains("MLDSAPrivateKey { alg: ML-DSA-87, pub_key_hash (tr):"));

        /*** MLDSAPublicKeyExpanded ***/
        let pk44_expanded = MLDSA44PublicKeyExpanded::from(&pk44);
        let pk65_expanded = MLDSA65PublicKeyExpanded::from(&pk65);
        let pk87_expanded = MLDSA87PublicKeyExpanded::from(&pk87);

        let sk44_expanded = MLDSA44PrivateKeyExpanded::from(&sk44);
        let sk65_expanded = MLDSA65PrivateKeyExpanded::from(&sk65);
        let sk87_expanded = MLDSA87PrivateKeyExpanded::from(&sk87);

        // fmt

        let pk_str = format!("{}", pk44_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-44, pub_key_hash (tr):"));

        let pk_str = format!("{}", pk65_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-65, pub_key_hash (tr):"));

        let pk_str = format!("{}", pk87_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-87, pub_key_hash (tr):"));

        // debug
        let pk_str = format!("{:?}", pk44_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-44, pub_key_hash (tr):"));

        let pk_str = format!("{:?}", pk65_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-65, pub_key_hash (tr):"));

        let pk_str = format!("{:?}", pk87_expanded);
        assert!(pk_str.contains("MLDSAPublicKeyExpanded { alg: ML-DSA-87, pub_key_hash (tr):"));

        /*** MLDSAPrivateKey ***/
        // fmt
        let sk_str = format!("{}", sk44_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-44, pub_key_hash (tr):"));

        let sk_str = format!("{}", sk65_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-65, pub_key_hash (tr):"));

        let sk_str = format!("{}", sk87_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-87, pub_key_hash (tr):"));

        // debug
        let sk_str = format!("{:?}", sk44_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-44, pub_key_hash (tr):"));

        let sk_str = format!("{:?}", sk65_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-65, pub_key_hash (tr):"));

        let sk_str = format!("{:?}", sk87_expanded);
        assert!(sk_str.contains("MLDSAPrivateKeyExpanded { alg: ML-DSA-87, pub_key_hash (tr):"));
    }
}
